/// Compatibility facade — re-exports from `package:navivox/core/gateway/client/navivox_gateway_config.dart`.
///
/// Import `package:navivox/core/gateway/client/navivox_gateway_config.dart`
/// or use the barrel via `package:navivox/core/gateway/navivox_gateway_protocol.dart`.
library;

export 'client/navivox_gateway_config.dart';

/// Compatibility facade — re-exports from `package:navivox/core/gateway/client/navivox_gateway_client.dart`.
///
/// Import `package:navivox/core/gateway/client/navivox_gateway_client.dart`
/// or use the barrel via `package:navivox/core/gateway/navivox_gateway_protocol.dart`.
library;

export 'client/navivox_gateway_client.dart';

import '../serialization/navivox_json.dart';

/// URI normalization helpers shared by Navivox pairing and setup flows.
const navivoxEndpointSchemes = {'http', 'https', 'ws', 'wss'};

bool navivoxIsEndpointScheme(String scheme) {
  return navivoxEndpointSchemes.contains(scheme.trim().toLowerCase());
}

String navivoxHttpSchemeFromEndpointScheme(
  String scheme, {
  String? descriptor,
}) {
  return switch (scheme.trim().toLowerCase()) {
    'ws' => 'http',
    'wss' => 'https',
    'http' => 'http',
    'https' => 'https',
    _ => throw FormatException(
      'Navivox endpoint URI must use ws, wss, http, or https',
      descriptor,
    ),
  };
}

String navivoxOriginFromUri(Uri uri) {
  return _navivoxOrigin(
    scheme: uri.scheme,
    host: uri.host,
    explicitPort: uri.hasPort ? uri.port : null,
  );
}

String _navivoxOrigin({
  required String scheme,
  required String host,
  required int? explicitPort,
}) {
  final formattedHost = host.contains(':') ? '[$host]' : host;
  final formattedPort = explicitPort == null ? '' : ':$explicitPort';
  return '$scheme://$formattedHost$formattedPort';
}

String navivoxHttpBaseUrlFromEndpointUri(Uri uri, {String? descriptor}) {
  final scheme = navivoxHttpSchemeFromEndpointScheme(
    uri.scheme,
    descriptor: descriptor,
  );
  if (uri.host.isEmpty) {
    throw FormatException(
      'Navivox endpoint URI must include a host',
      descriptor,
    );
  }
  return _navivoxOrigin(
    scheme: scheme,
    host: uri.host,
    explicitPort: uri.hasPort ? uri.port : null,
  );
}

String? navivoxHttpOriginOrOriginalFromString(String? raw) {
  final value = navivoxOptionalStringFromJson(raw);
  if (value == null) return null;
  final uri = Uri.tryParse(value);
  if (uri == null || !uri.hasScheme || uri.host.isEmpty) return value;
  final scheme = uri.scheme.toLowerCase();
  if (scheme != 'http' && scheme != 'https') return value;
  return navivoxOriginFromUri(uri);
}

Uri navivoxWebSocketUriFromEndpointString(String raw, {String? descriptor}) {
  final uri = Uri.parse(raw);
  if (uri.host.isEmpty) {
    throw FormatException(
      'Navivox websocket URI must include a host',
      descriptor,
    );
  }
  final scheme = uri.scheme.toLowerCase();
  if (scheme != 'ws' && scheme != 'wss') {
    throw FormatException(
      'Navivox websocket URI must use ws or wss',
      descriptor,
    );
  }
  return uri;
}

String? navivoxWebSocketUrlFromEndpointString(String? raw) {
  final value = navivoxOptionalStringFromJson(raw);
  if (value == null) return null;
  try {
    return navivoxWebSocketUriFromEndpointString(value).toString();
  } on FormatException {
    return null;
  }
}

String? navivoxHttpBaseUrlFromEndpointString(String? raw) {
  final uri = _endpointUriFromString(raw);
  if (uri == null || !navivoxIsEndpointScheme(uri.scheme)) return null;
  return navivoxHttpBaseUrlFromEndpointUri(uri);
}

Uri? _endpointUriFromString(String? raw) {
  final value = navivoxOptionalStringFromJson(raw);
  if (value == null) return null;
  final uri = Uri.tryParse(value);
  if (uri == null || !uri.hasScheme || uri.host.isEmpty) return null;
  return uri;
}

import '../../gateway/client/navivox_gateway_config.dart';
import '../endpoint/navivox_endpoint_uri.dart';
import '../serialization/navivox_json.dart';

class NavivoxPairingDescriptor {
  const NavivoxPairingDescriptor({
    required this.baseUri,
    required this.webSocketUri,
    required this.authMode,
    required this.exposureMode,
    required this.tokenRequired,
    this.token,
    this.serverId,
    this.profileId,
    this.workspaceId,
    this.providerId,
    this.channelIds = const [],
  });

  factory NavivoxPairingDescriptor.parse(String value) {
    final uri = Uri.parse(value.trim());
    if (uri.scheme != 'navivox' || uri.host != 'connect') {
      throw FormatException('Expected navivox://connect descriptor', value);
    }
    final query = navivoxFirstNonBlankQueryParameterValues(
      uri.queryParametersAll,
    );
    final tokenRequired = _boolFromPairingParam(query['token_required']);
    final token = _optionalPairingParam(query['rest_token']);
    if (tokenRequired && token == null) {
      throw FormatException('Pairing descriptor requires rest_token', value);
    }
    final webSocketUri = navivoxWebSocketUriFromEndpointString(
      _requiredPairingParam(query, 'websocket_url', value),
      descriptor: value,
    );
    final baseUri = _baseUriFromPairingParams(
      explicitBaseUrl: _optionalPairingParam(query['base_url']),
      webSocketUri: webSocketUri,
      descriptor: value,
    );
    return NavivoxPairingDescriptor(
      baseUri: baseUri,
      webSocketUri: webSocketUri,
      authMode: _optionalPairingParam(query['auth_mode']) ?? '',
      exposureMode: _optionalPairingParam(query['exposure_mode']) ?? '',
      tokenRequired: tokenRequired,
      token: token,
      serverId: _optionalPairingParam(query['server_id']),
      profileId: _optionalPairingParam(query['profile_id']),
      workspaceId: _optionalPairingParam(query['workspace_id']),
      providerId: _optionalPairingParam(query['provider_id']),
      channelIds: _csvPairingParam(query['channel_ids']),
    );
  }

  final Uri baseUri;
  final Uri webSocketUri;
  final String authMode;
  final String exposureMode;
  final bool tokenRequired;
  final String? token;
  final String? serverId;
  final String? profileId;
  final String? workspaceId;
  final String? providerId;
  final List<String> channelIds;

  NavivoxGatewayConfig toGatewayConfig() {
    return NavivoxGatewayConfig(
      baseUri: baseUri,
      token: token,
      webSocketUri: webSocketUri,
    );
  }
}

String _requiredPairingParam(
  Map<String, String> query,
  String name,
  String descriptor,
) {
  final value = _optionalPairingParam(query[name]);
  if (value == null) {
    throw FormatException('Pairing descriptor missing $name', descriptor);
  }
  return value;
}

String? _optionalPairingParam(String? value) {
  return navivoxOptionalStringFromJson(value);
}

Uri _baseUriFromPairingParams({
  required String? explicitBaseUrl,
  required Uri webSocketUri,
  required String descriptor,
}) {
  if (explicitBaseUrl != null) {
    return _httpBaseUriFromPairingParam(explicitBaseUrl, descriptor);
  }
  return Uri.parse(_baseUrlFromWebSocketUri(webSocketUri, descriptor));
}

Uri _httpBaseUriFromPairingParam(String value, String descriptor) {
  final uri = Uri.parse(value);
  final scheme = uri.scheme.toLowerCase();
  if ((scheme != 'http' && scheme != 'https') || uri.host.isEmpty) {
    throw FormatException(
      'Pairing descriptor base_url must use http or https',
      descriptor,
    );
  }
  return uri;
}

String _baseUrlFromWebSocketUri(Uri uri, String descriptor) {
  try {
    return navivoxHttpBaseUrlFromEndpointUri(uri, descriptor: descriptor);
  } on FormatException {
    throw FormatException(
      'Pairing descriptor invalid websocket_url',
      descriptor,
    );
  }
}

bool _boolFromPairingParam(String? value) {
  return navivoxStrictBoolFromJson(value);
}

List<String> _csvPairingParam(String? value) {
  final trimmed = navivoxOptionalStringFromJson(value);
  if (trimmed == null) return const [];
  return navivoxTrimmedStringList(trimmed.split(','));
}

import 'navivox_endpoint_uri.dart';

void main() {
  derivesHttpOriginFromWebSocketEndpointWithoutDroppingExplicitPort();
  stripsPathAndQueryOnlyForHttpBaseUrlDerivation();
  preservesWebSocketPathAndQueryForConnectionEndpoint();
  keepsOriginalValueWhenHttpOriginCannotBeDerived();
}

void derivesHttpOriginFromWebSocketEndpointWithoutDroppingExplicitPort() {
  final result = navivoxHttpBaseUrlFromEndpointString(
    'wss://gateway.example:443/navivox/ws?token=secret',
  );

  _expect(
    result == 'https://gateway.example:443',
    'explicit default ports are part of the endpoint origin contract',
  );
}

void stripsPathAndQueryOnlyForHttpBaseUrlDerivation() {
  final result = navivoxHttpBaseUrlFromEndpointString(
    'https://gateway.example:8443/api?token=secret',
  );

  _expect(result == 'https://gateway.example:8443', 'base URL is origin only');
}

void preservesWebSocketPathAndQueryForConnectionEndpoint() {
  final result = navivoxWebSocketUrlFromEndpointString(
    'wss://gateway.example/navivox/ws?token=secret',
  );

  _expect(
    result == 'wss://gateway.example/navivox/ws?token=secret',
    'websocket endpoint keeps path/query while base URL derivation strips them',
  );
}

void keepsOriginalValueWhenHttpOriginCannotBeDerived() {
  final result = navivoxHttpOriginOrOriginalFromString(
    'ftp://gateway.example/resource',
  );

  _expect(
    result == 'ftp://gateway.example/resource',
    'non-HTTP values are preserved for compatibility instead of rejected',
  );
}

void _expect(bool condition, String message) {
  if (!condition) throw StateError(message);
}

import 'navivox_voice_run.dart';

void main() {
  markSubmittedDoesNotCarryStaleFailureReason();
  markSubmittedUsesCurrentNullableSession();
}

void markSubmittedDoesNotCarryStaleFailureReason() {
  final failedRun = _pendingRun().markFailed('Gateway is not connected.');

  final submitted = failedRun.markSubmitted(
    requestId: 'request-2',
    sessionId: 'session-2',
  );

  _expect(
    submitted.status == NavivoxVoiceRunStatus.submitted,
    'run should be submitted after retry transition',
  );
  _expect(
    submitted.reason == null,
    'submitted retry should not keep a stale terminal failure reason',
  );
}

void markSubmittedUsesCurrentNullableSession() {
  final submittedRun = _pendingRun().markSubmitted(
    requestId: 'request-1',
    sessionId: 'session-1',
  );

  final resubmitted = submittedRun.markSubmitted(
    requestId: 'request-2',
    sessionId: null,
  );

  _expect(
    resubmitted.requestId == 'request-2',
    'resubmission should replace the request id',
  );
  _expect(
    resubmitted.sessionId == null,
    'resubmission should reflect the current absent session id',
  );
}

NavivoxVoiceRun _pendingRun() {
  return NavivoxVoiceRun.recording(
    id: 'voice-1',
    serverId: 'server-1',
    profileId: 'profile-1',
    createdAt: DateTime.utc(2026),
  ).withDeviceTranscript(
    transcript: 'hello',
    duration: const Duration(milliseconds: 500),
    confidence: 0.9,
    updatedAt: DateTime.utc(2026, 1, 1, 0, 0, 1),
  );
}

void _expect(bool condition, String message) {
  if (!condition) throw StateError(message);
}

/// Shared coercion helpers for Navivox wire-protocol JSON payloads.
///
/// These helpers intentionally accept loose `Object?` values because gateway and
/// memory endpoints can be decoded from typed maps, platform channels, or JSON
/// maps with dynamic keys.
String navivoxStringFromJson(Object? value, {required String fallback}) {
  final text = value?.toString().trim();
  if (text == null || text.isEmpty) return fallback;
  return text;
}

String? navivoxOptionalStringFromJson(Object? value) {
  final text = value?.toString().trim();
  if (text == null || text.isEmpty) return null;
  return text;
}

/// Returns a trimmed string only when [value] is already a literal string.
String? navivoxOptionalLiteralStringFromJson(Object? value) {
  if (value is! String) return null;
  final text = value.trim();
  return text.isEmpty ? null : text;
}

int navivoxIntFromJson(Object? value) {
  if (value is int) return value;
  if (value is num) return value.toInt();
  return int.tryParse(value?.toString() ?? '') ?? 0;
}

double? navivoxDoubleFromJson(Object? value) {
  if (value is double) return value;
  if (value is num) return value.toDouble();
  return double.tryParse(value?.toString() ?? '');
}

bool navivoxBoolFromJson(Object? value, {bool fallback = false}) {
  if (value is bool) return value;
  final text = value?.toString().trim().toLowerCase();
  if (text == 'true' || text == '1' || text == 'yes') return true;
  if (text == 'false' || text == '0' || text == 'no') return false;
  return fallback;
}

/// Returns only literal bool values or `true`/`false` string tokens.
///
/// Use this for protocol flags whose existing contract intentionally does not
/// accept broader truthy aliases such as `1` or `yes`.
bool navivoxStrictBoolFromJson(Object? value, {bool fallback = false}) {
  if (value is bool) return value;
  final text = value?.toString().trim().toLowerCase();
  if (text == 'true') return true;
  if (text == 'false') return false;
  return fallback;
}

Map<String, Object?> navivoxMapFromJson(Object? value) {
  if (value is! Map) return const {};
  return Map<String, Object?>.from(value);
}

Map<String, Object?> navivoxMapFieldFromJson(
  Map<String, Object?> json,
  String key,
) {
  return navivoxMapFromJson(json[key]);
}

List<Object?> navivoxListFromJson(Object? value) {
  if (value is! List) return const [];
  return value.cast<Object?>();
}

/// Returns map entries from a loose wire list, ignoring non-map items.
List<Map<String, Object?>> navivoxMapListFromJson(Object? value) {
  return navivoxListFromJson(
    value,
  ).whereType<Map>().map(navivoxMapFromJson).toList(growable: false);
}

List<Object?> navivoxListFieldFromJson(Map<String, Object?> json, String key) {
  return navivoxListFromJson(json[key]);
}

List<String> navivoxStringListFromJson(Object? value) {
  if (value is! List) return const [];
  return navivoxTrimmedStringList(value);
}

String navivoxStringFieldFromJson(Map<String, Object?> json, String key) {
  return navivoxStringFromJson(json[key], fallback: '');
}

/// Selects a typed enum/value object by matching its wire value.
///
/// The wire token uses the same non-empty trimmed string semantics as other
/// Navivox protocol fields and falls back when the value is blank or unknown.
T navivoxValueFromWire<T>({
  required Object? value,
  required Iterable<T> values,
  required String Function(T value) wireValue,
  required T fallback,
}) {
  final text = navivoxOptionalStringFromJson(value);
  if (text == null) return fallback;
  for (final candidate in values) {
    if (wireValue(candidate) == text) return candidate;
  }
  return fallback;
}

/// Returns the first non-empty literal string field whose key matches [names].
///
/// The lookup first honors exact keys, then falls back to a compatibility match
/// that ignores underscores and case so wire payloads can use either
/// `snake_case` or `camelCase` aliases without each parser reimplementing that
/// policy. Non-string values are intentionally ignored to preserve strict wire
/// semantics for IDs, URLs, and tokens.
String? navivoxFirstStringFieldFromJson(
  Map<dynamic, dynamic> json,
  Iterable<String> names,
) {
  for (final name in names) {
    final exact = navivoxOptionalLiteralStringFromJson(json[name]);
    if (exact != null) return exact;
  }
  final normalizedNames = {
    for (final name in names) _navivoxNormalizeJsonFieldName(name),
  };
  for (final entry in json.entries) {
    if (!normalizedNames.contains(
      _navivoxNormalizeJsonFieldName('${entry.key}'),
    )) {
      continue;
    }
    final value = navivoxOptionalLiteralStringFromJson(entry.value);
    if (value != null) return value;
  }
  return null;
}

String _navivoxNormalizeJsonFieldName(String value) =>
    value.toLowerCase().replaceAll('_', '');

List<String> navivoxStringListFieldFromJson(
  Map<String, Object?> json,
  String key,
) {
  return navivoxStringListFromJson(json[key]);
}

/// Returns non-empty trimmed string values in their original order.
List<String> navivoxTrimmedStringList(Iterable<Object?> values) {
  return values
      .map((item) => item.toString().trim())
      .where((item) => item.isNotEmpty)
      .toList(growable: false);
}

/// Returns a string map with null/blank values removed and remaining values
/// trimmed. Useful for query params and wire request bodies that share Navivox
/// non-empty string field semantics.
Map<String, String> navivoxTrimmedStringFields(Map<String, Object?> values) {
  return {
    for (final entry in values.entries)
      if (entry.value case final value?)
        if (value.toString().trim().isNotEmpty)
          entry.key: value.toString().trim(),
  };
}

/// Returns a query-parameter map using the first non-empty value for each key.
///
/// This keeps copied URLs with duplicate blank parameters from erasing the
/// earlier value supplied by the producer.
Map<String, String> navivoxFirstNonBlankQueryParameterValues(
  Map<String, List<String>> queryParametersAll,
) {
  final result = <String, String>{};
  for (final entry in queryParametersAll.entries) {
    final value = navivoxFirstNonBlankQueryParameterValue(entry.value);
    if (value != null) result[entry.key] = value;
  }
  return result;
}

String? navivoxFirstNonBlankQueryParameterValue(List<String> values) {
  for (final value in values) {
    final text = navivoxOptionalLiteralStringFromJson(value);
    if (text != null) return text;
  }
  return null;
}

DateTime? navivoxDateTimeFromJson(Object? value) {
  final text = value?.toString().trim();
  if (text == null || text.isEmpty) return null;
  return DateTime.tryParse(text);
}

