import 'session_persistence_service.dart';

void main() {
  saveConnectionFieldsClearBlankOptionalValues();
}

void saveConnectionFieldsClearBlankOptionalValues() {
  final fields = SavedConnectionFields.fromInput(
    baseUrl: ' https://gateway.example/api ',
    webSocketUrl: '   ',
    gatewayId: null,
  );

  _expect(fields.baseUrl == 'https://gateway.example/api', 'base URL is trimmed');
  _expect(
    fields.webSocketUrl == null,
    'blank websocket URL must clear stale persisted websocket metadata',
  );
  _expect(
    fields.gatewayId == null,
    'absent gateway id must clear stale persisted gateway metadata',
  );
}

void _expect(bool condition, String message) {
  if (!condition) throw StateError(message);
}

import 'package:flutter_test/flutter_test.dart';

import 'session_persistence_service.dart';

void main() {
  test('save connection fields clear blank optional values', () {
    final fields = SavedConnectionFields.fromInput(
      baseUrl: ' https://gateway.example/api ',
      webSocketUrl: '   ',
      gatewayId: null,
    );

    expect(fields.baseUrl, 'https://gateway.example/api');
    expect(
      fields.webSocketUrl,
      isNull,
      reason: 'blank websocket URL must clear stale persisted websocket metadata',
    );
    expect(
      fields.gatewayId,
      isNull,
      reason: 'absent gateway id must clear stale persisted gateway metadata',
    );
  });
}

